## 4. gRPC Proto 설계

### 4-1. User Service

```protobuf
// 파일: protobuf/src/main/proto/user/user.proto
syntax = "proto3";
package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service UserService {
  rpc GetUser(GetUserRequest) returns (GetUserResponse);
  rpc GetUsers(GetUsersRequest) returns (GetUsersResponse);
  rpc UpdateUser(UpdateUserRequest) returns (UpdateUserResponse);
  rpc DeactivateUser(DeactivateUserRequest) returns (DeactivateUserResponse);
  rpc GetMannerScore(GetMannerScoreRequest) returns (GetMannerScoreResponse);
}

message User {
  string id = 1;
  string nickname = 2;
  string phone_number = 3;
  optional string profile_image_url = 4;
  string gender = 5;
  int32 birth_year = 6;
  optional string bio = 7;
  float manner_score = 8;
  bool is_active = 9;
  string created_at = 10;
  string updated_at = 11;
}

message GetUserRequest { string user_id = 1; }
message GetUserResponse { User user = 1; }

message GetUsersRequest { repeated string user_ids = 1; }
message GetUsersResponse { repeated User users = 1; }
```

### 4-2. Call Service

```protobuf
// 파일: protobuf/src/main/proto/call/call.proto
syntax = "proto3";
package call;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.call";

service CallService {
  rpc RequestCall(RequestCallRequest) returns (RequestCallResponse);
  rpc AcceptCall(AcceptCallRequest) returns (AcceptCallResponse);
  rpc RejectCall(RejectCallRequest) returns (RejectCallResponse);
  rpc EndCall(EndCallRequest) returns (EndCallResponse);
  rpc ListCallHistory(ListCallHistoryRequest) returns (ListCallHistoryResponse);
  rpc RateCall(RateCallRequest) returns (RateCallResponse);
}

enum CallStatus {
  CALL_STATUS_UNSPECIFIED = 0;
  CALL_STATUS_RINGING = 1;
  CALL_STATUS_ONGOING = 2;
  CALL_STATUS_ENDED = 3;
  CALL_STATUS_MISSED = 4;
  CALL_STATUS_REJECTED = 5;
}

message Call {
  string id = 1;
  string caller_id = 2;
  string receiver_id = 3;
  CallStatus status = 4;
  optional int32 duration_seconds = 5;
  optional string started_at = 6;
  optional string ended_at = 7;
  string created_at = 8;
}

message ListCallHistoryRequest {
  string user_id = 1;
  int32 limit = 2;
  int32 offset = 3;
}
message ListCallHistoryResponse {
  repeated Call calls = 1;
  int32 total_count = 2;
}
```

